const update = $json;
const message = update.message || null;
const callback = update.callback_query || null;

let eventType = 'unknown';
let chatId = null;
let userText = '';
let callbackData = '';
let callbackQueryId = '';
let userId = null;
let username = '';
let messageId = null;
let isTextMessage = false;

if (message) {
  eventType = 'message';
  chatId = message.chat?.id ?? null;
  userText = (message.text ?? '').trim();
  userId = message.from?.id ?? null;
  username = message.from?.username ?? '';
  messageId = message.message_id ?? null;
  isTextMessage = Boolean(message.text);
} else if (callback) {
  eventType = 'callback';
  chatId = callback.message?.chat?.id ?? callback.from?.id ?? null;
  callbackData = (callback.data ?? '').trim();
  callbackQueryId = callback.id ?? '';
  userId = callback.from?.id ?? null;
  username = callback.from?.username ?? '';
  messageId = callback.message?.message_id ?? null;
}

const executionKey = String(
  $json.executionKey ||
  update.update_id ||
  callbackQueryId ||
  (chatId ? `chat:${chatId}:${Date.now()}` : Date.now())
);

return [{
  json: {
    ...$json,
    eventType,
    chatId,
    userText,
    callbackData,
    callbackQueryId,
    updateId: update.update_id ?? null,
    userId,
    username,
    messageId,
    isTextMessage,
    executionKey,
    raw: update
  }
}];

if (!$json.executionKey) {
  return [{
    json: {
      ...$json,
      stage: $json.stage || 'AI',
      stageOk: false,
      stopExecution: true,
      errorMessage: 'missing_execution_key'
    }
  }];
}

const provider = 'openai';
const fallbackProvider = 'deepseek';
const stage = 'AI';

const staticData = getWorkflowStaticData('global');
if (!staticData.generationBudgetGuard) staticData.generationBudgetGuard = {};

const budgetKey = $json.targetContentId || $json.contentId || ($json.chatId ? `chat:${$json.chatId}` : 'unknown');
const stageFailures = Number(staticData.generationBudgetGuard?.[budgetKey]?.[stage] || 0);
if (stageFailures >= 3) {
  return [{
    json: {
      ...$json,
      stage,
      stageOk: false,
      aiParseOk: false,
      stopExecution: true,
      generationBudgetExceeded: true,
      errorStage: 'AI_REQUEST',
      errorMessage: 'generation_budget_exceeded'
    }
  }];
}

let AI_API_KEY = '';
try {
  AI_API_KEY = String(($env && $env.AI_API_KEY) || '').trim();
} catch (e) {
  AI_API_KEY = '';
}

const API_URL = 'https://api.aitunnel.ru/v1/chat/completions';
const OPENAI_MODEL = 'gpt-4o-mini';
const DEEPSEEK_MODEL = 'deepseek-chat';

const generationType = $json.generationType || 'new';
const contentMode = ['image_to_video', 'direct_video'].includes($json.contentMode)
  ? $json.contentMode
  : 'image_to_video';
const voiceMode = $json.voiceMode || 'elevenlabs';

const rawUserText = String($json.userText || '').trim();
const fallbackPrompt = 'Придумай вирусную идею для TikTok';
const sourceText = (rawUserText || fallbackPrompt).replace(/\s+/g, ' ').trim().slice(0, 3000);
const revisionReason = String($json.revisionReason || '').trim().slice(0, 1000);

if (!AI_API_KEY) {
  return [{
    json: {
      ...$json,
      stage,
      stageOk: false,
      aiParseOk: false,
      errorStage: 'AI_REQUEST',
      errorMessage: 'provider_not_configured: ai_api_key',
      stopExecution: true
    }
  }];
}

if (!sourceText) {
  return [{
    json: {
      ...$json,
      stage,
      stageOk: false,
      aiParseOk: false,
      errorStage: 'AI_REQUEST',
      errorMessage: 'empty_ai_prompt',
      stopExecution: true
    }
  }];
}

const baseDraft = $json.baseDraft || null;
const previousScript = String(baseDraft?.script || '').trim().slice(0, 2000);

const systemPrompt = [
  'Ты создаёшь вирусные TikTok сценарии.',
  'Ответ всегда должен быть валидным JSON.',
  'Никогда не возвращай пустой объект.',
  'Если не уверен — придумай лучший возможный вариант.',
  'Пиши только на русском языке.',
  'Длительность 30-40 секунд.',
  'Формат строго:',
  '{"title":"...","script":"...","voiceover":"..."}'
].join('\n');

const userPrompt = generationType === 'revision'
  ? [
      `Контент ID: ${$json.targetContentId || 'unknown'}`,
      `Режим: ${contentMode}`,
      `Голос: ${voiceMode}`,
      'Это переработка сценария.',
      `Замечание пользователя: ${revisionReason || 'Сделай лучше и интереснее'}`,
      `Предыдущий сценарий: ${previousScript || 'нет данных'}`,
      'Сохрани тему, но усили хук и удержание.'
    ].join('\n')
  : [
      `Режим: ${contentMode}`,
      `Голос: ${voiceMode}`,
      `Запрос пользователя:\n${sourceText}`
    ].join('\n');

const messages = [
  { role: 'system', content: systemPrompt },
  { role: 'user', content: userPrompt }
];

const auth = `Bearer ${AI_API_KEY}`;

const aiPrimaryRequest = {
  url: API_URL,
  headers: {
    Authorization: auth,
    'Content-Type': 'application/json'
  },
  body: {
    model: OPENAI_MODEL,
    temperature: 0.8,
    response_format: { type: 'json_object' },
    messages
  }
};

const aiFallbackRequest = {
  url: API_URL,
  headers: {
    Authorization: auth,
    'Content-Type': 'application/json'
  },
  body: {
    model: DEEPSEEK_MODEL,
    temperature: 0.8,
    response_format: { type: 'json_object' },
    messages
  }
};

return [{
  json: {
    ...$json,
    stage,
    stageOk: true,
    provider,
    fallbackProvider,
    generationType,
    contentMode,
    voiceMode,
    aiPrimaryRequest,
    aiFallbackRequest
  }
}];

if (!$json.executionKey) {
  return [{
    json: {
      ...$json,
      stage: $json.stage || 'AI',
      stageOk: false,
      stopExecution: true,
      errorMessage: 'missing_execution_key'
    }
  }];
}

function asText(value) {
  if (typeof value === 'string') return value.trim();
  if (Array.isArray(value)) {
    return value
      .map((item) => {
        if (typeof item === 'string') return item;
        if (item && typeof item === 'object') {
          if (typeof item.text === 'string') return item.text;
          if (typeof item.content === 'string') return item.content;
        }
        return '';
      })
      .join('\n')
      .trim();
  }
  if (value && typeof value === 'object') {
    if (typeof value.text === 'string') return value.text.trim();
    if (typeof value.content === 'string') return value.content.trim();
  }
  return '';
}

function stripFences(raw) {
  return String(raw || '')
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/\s*```\s*$/i, '')
    .trim();
}

function parseJsonCandidate(candidate) {
  if (candidate == null) return null;
  if (typeof candidate === 'object' && !Array.isArray(candidate)) return candidate;

  const text = asText(candidate);
  if (!text) return null;

  const cleaned = stripFences(text);
  if (!cleaned) return null;

  try {
    return JSON.parse(cleaned);
  } catch (_) {
    const start = cleaned.indexOf('{');
    const end = cleaned.lastIndexOf('}');
    if (start !== -1 && end > start) {
      return JSON.parse(cleaned.slice(start, end + 1));
    }
    throw new Error('AI returned non-JSON content');
  }
}

function extractRawAi(payload) {
  const raw =
    payload?.choices?.[0]?.message?.content ??
    payload?.data?.choices?.[0]?.message?.content ??
    payload?.message?.content ??
    payload?.content ??
    '';
  const text = asText(raw);
  return text ? String(text).slice(0, 300) : null;
}

function extractParsedObject(payload) {
  const candidates = [
    payload?.choices?.[0]?.message?.content,
    payload?.data?.choices?.[0]?.message?.content,
    payload?.message?.content,
    payload?.content,
    payload?.aiParsed,
    payload
  ];

  let lastError = null;
  for (const candidate of candidates) {
    try {
      const parsed = parseJsonCandidate(candidate);
      if (parsed && typeof parsed === 'object' && !Array.isArray(parsed)) {
        return parsed;
      }
    } catch (e) {
      lastError = e;
    }
  }

  if (lastError) throw lastError;
  throw new Error('AI response content is empty');
}

function normalizeRequired(parsed) {
  const title = typeof parsed.title === 'string' ? parsed.title.trim() : '';
  const script = typeof parsed.script === 'string' ? parsed.script.trim() : '';
  const voiceover = typeof parsed.voiceover === 'string' ? parsed.voiceover.trim() : '';

  if (!title || !script || !voiceover) {
    throw new Error('AI JSON must include non-empty title, script, and voiceover');
  }

  return { title, script, voiceover };
}

try {
  if ($json?.error) {
    const err = $json.error;
    const msg = err.message || err.description || JSON.stringify(err);
    return [{
      json: {
        ...$json,
        stage: 'AI',
        stageOk: false,
        aiParseOk: false,
        errorStage: 'AI_PARSE',
        errorMessage: 'AI HTTP error: ' + String(msg || 'unknown_error'),
        rawAi: extractRawAi($json)
      }
    }];
  }

  const parsedObj = extractParsedObject($json);
  const normalized = normalizeRequired(parsedObj);

  return [{
    json: {
      ...$json,
      stage: 'AI',
      stageOk: true,
      aiParseOk: true,
      aiParsed: {
        ...parsedObj,
        title: normalized.title,
        script: normalized.script,
        voiceover: normalized.voiceover
      },
      title: normalized.title,
      script: normalized.script,
      voiceover: normalized.voiceover,
      errorStage: null,
      errorMessage: null,
      rawAi: extractRawAi($json)
    }
  }];
} catch (err) {
  return [{
    json: {
      ...$json,
      stage: 'AI',
      stageOk: false,
      aiParseOk: false,
      errorStage: 'AI_PARSE',
      errorMessage: String(err?.message || err || 'AI parse error'),
      rawAi: extractRawAi($json)
    }
  }];
}

function generateContentId() {
  return `${Date.now().toString(36)}${Math.random().toString(36).slice(2, 7)}`.slice(0, 18);
}

const staticData = getWorkflowStaticData('global');
if (!staticData.drafts) staticData.drafts = {};
if (!staticData.approved) staticData.approved = {};
if (!staticData.logs) staticData.logs = [];
if (!staticData.processedCallbacks) staticData.processedCallbacks = {};
if (!staticData.awaitingRevisionFeedback) staticData.awaitingRevisionFeedback = {};
if (!staticData.analytics) staticData.analytics = {};

const now = new Date().toISOString();
const generationType = $json.generationType || 'new';
const rawAiPreview = String($json.rawAi || '').slice(0, 300);

let contentId = $json.targetContentId || $json.contentId || null;
if (!contentId || (generationType === 'new' && !staticData.drafts[contentId])) {
  contentId = generateContentId();
}

let draft = staticData.drafts[contentId] || {
  contentId,
  createdAt: now,
  revisions: {},
  revisionCount: 0
};

const prevRevisionCount = Number(draft.revisionCount || 0);
let revisionId = $json.nextRevisionId || $json.revisionId || null;
if (!revisionId) {
  revisionId = prevRevisionCount > 0 ? `rev${prevRevisionCount + 1}` : 'rev1';
}

const parsedRev = Number(String(revisionId).replace(/[^0-9]/g, '')) || (prevRevisionCount + 1) || 1;
const revisionCount = Math.max(prevRevisionCount, parsedRev, 1);

const contentMode = ['image_to_video', 'direct_video'].includes($json.contentMode) ? $json.contentMode : (draft.contentMode || 'image_to_video');
const voiceMode = ($json.voiceMode || draft.voiceMode || 'elevenlabs');
const targetDurationSec = Number($json.targetDurationSec || 45);
const actualDurationSec = Number($json.actualDurationSec || 0);

const revisionReason = generationType === 'revision'
  ? String($json.revisionReason || draft.revisionReason || '').trim()
  : null;

const scenes = Array.isArray($json.scenes) ? $json.scenes : [];
const visualPrompts = Array.isArray($json.visualPrompts) ? $json.visualPrompts : [];
const hashtags = Array.isArray($json.hashtags) ? $json.hashtags : [];
const imageAssets = Array.isArray($json.imageAssets) ? $json.imageAssets : [];
const sceneVideos = Array.isArray($json.sceneVideos) ? $json.sceneVideos : [];
const caption = String($json.caption || '').trim();

const publishPayload = {
  caption,
  hashtags,
  durationSec: actualDurationSec || targetDurationSec,
  finalVideoUrl: $json.finalVideoUrl || ''
};

const revisionRecord = {
  revisionId,
  createdAt: now,
  revisionReason,
  title: $json.title,
  script: $json.script,
  voiceover: $json.voiceover,
  topicHint: $json.topicHint || null,
  targetDurationSec,
  actualDurationSec,
  hashtags,
  caption,
  publishPayload,
  videoModerationStatus: 'pending',
  contentPlan: {
    scenes,
    visualPrompts,
    caption,
    hashtags,
    targetDurationSec,
    actualDurationSec
  },
  assets: {
    imageAssets,
    sceneVideos,
    voiceoverUrl: $json.voiceoverAssetUrl || '',
    finalVideoUrl: $json.finalVideoUrl || '',
    previewUrl: $json.previewUrl || $json.finalVideoUrl || ''
  },
  status: 'pending',
  provider: $json.providerUsed || $json.provider || null,
  contentMode,
  voiceMode,
  errorMessage: null,
  rawAiPreview
};

if (!draft.revisions) draft.revisions = {};
draft.revisions[revisionId] = revisionRecord;

draft.currentRevisionId = revisionId;
draft.revisionCount = revisionCount;
draft.status = 'pending';
draft.videoModerationStatus = 'pending';
draft.updatedAt = now;
draft.createdAt = draft.createdAt || now;
draft.chatId = $json.chatId;
draft.userId = $json.userId || draft.userId || null;
draft.username = $json.username || draft.username || '';
draft.provider = revisionRecord.provider;
draft.contentMode = contentMode;
draft.voiceMode = voiceMode;
draft.title = $json.title;
draft.script = $json.script;
draft.voiceover = $json.voiceover;
draft.topicHint = $json.topicHint || draft.topicHint || null;
draft.targetDurationSec = targetDurationSec;
draft.actualDurationSec = actualDurationSec;
draft.caption = caption;
draft.hashtags = hashtags;
draft.publishPayload = publishPayload;
draft.finalVideoUrl = revisionRecord.assets.finalVideoUrl || draft.finalVideoUrl || '';
draft.previewUrl = revisionRecord.assets.previewUrl || draft.previewUrl || '';
draft.revisionReason = revisionReason;
draft.revisionRequestedAt = generationType === 'revision' ? now : (draft.revisionRequestedAt || null);

staticData.drafts[contentId] = draft;
delete staticData.awaitingRevisionFeedback[String($json.chatId || '')];

staticData.analytics[contentId] = {
  chatId: draft.chatId,
  userId: draft.userId,
  contentMode,
  voiceMode,
  revisionCount,
  targetDurationSec,
  actualDurationSec,
  hashtagsCount: hashtags.length,
  lastStatus: 'pending',
  updatedAt: now
};

staticData.logs.push({
  timestamp: now,
  event: generationType === 'revision' ? 'draft_revised' : 'draft_created',
  contentId,
  revisionId,
  revisionReason,
  contentMode,
  voiceMode,
  status: 'pending',
  provider: draft.provider,
  errorMessage: null,
  rawAi: rawAiPreview || null
});

return [{
  json: {
    ...$json,
    contentId,
    revisionId,
    revisionCount,
    createdAt: draft.createdAt,
    status: 'pending',
    scenes,
    visualPrompts,
    contentMode,
    voiceMode,
    targetDurationSec,
    actualDurationSec,
    hashtags,
    caption,
    publishPayload,
    previewUrl: draft.previewUrl || '',
    finalVideoUrl: draft.finalVideoUrl || '',
    draft
  }
}];

const normalized = $items('Function (Normalize Input)', 0, 0)[0].json;
const merged = { ...$json, ...(normalized || {}) };

const staticData = getWorkflowStaticData('global');
if (!staticData.drafts) staticData.drafts = {};
if (!staticData.approved) staticData.approved = {};
if (!staticData.logs) staticData.logs = [];
if (!staticData.processedCallbacks) staticData.processedCallbacks = {};
if (!staticData.awaitingRevisionFeedback) staticData.awaitingRevisionFeedback = {};

const MAX_REVISIONS = 5;
const callbackData = normalized.callbackData || '';
const [actionRaw, contentIdRaw, revisionIdRaw] = callbackData.split(':');
const action = (actionRaw || '').trim();
const contentId = (contentIdRaw || '').trim();
const requestedRevisionId = (revisionIdRaw || '').trim();

const allowedActions = ['approve', 'reject', 'revise', 'video_approve', 'video_reject', 'stop', 'recreate'];
const videoActions = ['video_approve', 'video_reject', 'stop', 'recreate'];

let callbackValid = true;
let invalidReason = '';

if (!normalized.callbackQueryId) {
  callbackValid = false;
  invalidReason = 'missing_callback_query_id';
}

if (callbackValid && staticData.processedCallbacks[normalized.callbackQueryId]) {
  callbackValid = false;
  invalidReason = 'duplicate_callback';
}

if (callbackValid && !allowedActions.includes(action)) {
  callbackValid = false;
  invalidReason = 'invalid_action';
}

if (callbackValid && !contentId) {
  callbackValid = false;
  invalidReason = 'missing_content_id';
}

const draft = contentId ? staticData.drafts[contentId] : null;
if (callbackValid && !draft) {
  callbackValid = false;
  invalidReason = 'draft_not_found';
}

const revisionId = (draft && (requestedRevisionId || draft.currentRevisionId)) || '';
const revision = draft?.revisions?.[revisionId] || null;

if (callbackValid && !revision) {
  callbackValid = false;
  invalidReason = 'revision_not_found';
}

if (callbackValid && ['approve', 'reject', 'revise'].includes(action) && draft.status !== 'pending') {
  callbackValid = false;
  invalidReason = `already_${draft.status}`;
}

if (callbackValid && ['video_approve', 'video_reject', 'stop'].includes(action) && draft.status !== 'approved_pending_video') {
  callbackValid = false;
  invalidReason = `invalid_video_state_${draft.status}`;
}

if (callbackValid && action === 'recreate' && !['approved_pending_video', 'video_rejected'].includes(draft.status)) {
  callbackValid = false;
  invalidReason = `invalid_recreate_state_${draft.status}`;
}

if (callbackValid && ['revise', 'recreate'].includes(action) && Number(draft.revisionCount || 0) >= MAX_REVISIONS) {
  callbackValid = false;
  invalidReason = 'revision_limit_reached';
}

if (callbackValid && action === 'revise' && draft.status === 'rejected') {
  callbackValid = false;
  invalidReason = 'already_rejected';
}

if (normalized.callbackQueryId && !staticData.processedCallbacks[normalized.callbackQueryId]) {
  staticData.processedCallbacks[normalized.callbackQueryId] = true;
}

const now = new Date().toISOString();
staticData.logs.push({
  timestamp: now,
  event: 'callback_received',
  contentId: contentId || null,
  revisionId: revisionId || null,
  revisionReason: draft?.revisionReason || null,
  contentMode: draft?.contentMode || null,
  voiceMode: draft?.voiceMode || null,
  status: callbackValid ? 'accepted' : 'ignored',
  provider: revision?.provider || draft?.provider || null,
  errorMessage: callbackValid ? null : invalidReason,
  rawAi: revision?.rawAiPreview || null
});

return [{
  json: {
    ...merged,
    executionKey: $json.executionKey || normalized?.executionKey || merged.executionKey || null,
    action,
    contentId,
    revisionId,
    callbackValid,
    invalidReason,
    isVideoModerationAction: videoActions.includes(action),
    isVideoApprove: action === 'video_approve',
    isVideoReject: action === 'video_reject',
    isStop: action === 'stop',
    isRecreate: action === 'recreate',
    draft: draft || null,
    revision: revision || null
  }
}];

const staticData = getWorkflowStaticData('global');
if (!staticData.drafts) staticData.drafts = {};
if (!staticData.approved) staticData.approved = {};
if (!staticData.logs) staticData.logs = [];
if (!staticData.analytics) staticData.analytics = {};

const contentId = $json.contentId;
const revisionId = $json.revisionId;
const draft = staticData.drafts[contentId] || $json.draft;

if (!draft) {
  return [{ json: { ...$json, status: 'error', errorMessage: 'draft_not_found' } }];
}

const revision = draft?.revisions?.[revisionId] || null;
if (!revision) {
  return [{ json: { ...$json, status: 'error', errorMessage: 'revision_not_found', chatId: draft.chatId } }];
}

if (draft.status !== 'pending') {
  staticData.logs.push({
    timestamp: new Date().toISOString(),
    event: 'approve_skipped',
    contentId,
    revisionId,
    revisionReason: draft.revisionReason || null,
    contentMode: draft.contentMode || null,
    voiceMode: draft.voiceMode || null,
    status: draft.status,
    provider: revision.provider || draft.provider || null,
    errorMessage: `already_${draft.status}`,
    rawAi: revision.rawAiPreview || null
  });

  return [{
    json: {
      ...$json,
      ...draft,
      status: draft.status,
      chatId: draft.chatId
    }
  }];
}

const now = new Date().toISOString();
draft.status = 'approved_pending_video';
draft.videoModerationStatus = 'pending';
draft.currentRevisionId = revisionId;
draft.updatedAt = now;

revision.status = 'approved_pending_video';
revision.videoModerationStatus = 'pending';
revision.videoModerationRequestedAt = now;

const finalVideoUrl = revision.assets?.finalVideoUrl || draft.finalVideoUrl || '';
const previewUrl = revision.assets?.previewUrl || draft.previewUrl || finalVideoUrl;

draft.finalVideoUrl = finalVideoUrl;
draft.previewUrl = previewUrl;
draft.title = revision.title || draft.title;
draft.script = revision.script || draft.script;
draft.voiceover = revision.voiceover || draft.voiceover;
draft.hashtags = revision.hashtags || draft.hashtags || [];
draft.caption = revision.caption || draft.caption || '';
draft.targetDurationSec = revision.targetDurationSec || draft.targetDurationSec || 45;
draft.actualDurationSec = revision.actualDurationSec || draft.actualDurationSec || 0;
draft.publishPayload = revision.publishPayload || draft.publishPayload || {
  caption: draft.caption || '',
  hashtags: draft.hashtags || [],
  durationSec: draft.actualDurationSec || draft.targetDurationSec || 45,
  finalVideoUrl: finalVideoUrl
};

staticData.drafts[contentId] = draft;

staticData.analytics[contentId] = {
  ...(staticData.analytics[contentId] || {}),
  contentMode: draft.contentMode || null,
  voiceMode: draft.voiceMode || null,
  revisionCount: draft.revisionCount || 1,
  targetDurationSec: draft.targetDurationSec || 45,
  actualDurationSec: draft.actualDurationSec || 0,
  hashtagsCount: Array.isArray(draft.hashtags) ? draft.hashtags.length : 0,
  lastStatus: 'approved_pending_video',
  updatedAt: now
};

staticData.logs.push({
  timestamp: now,
  event: 'video_moderation_pending',
  contentId,
  revisionId,
  revisionReason: revision.revisionReason || draft.revisionReason || null,
  contentMode: draft.contentMode || null,
  voiceMode: draft.voiceMode || null,
  status: 'approved_pending_video',
  provider: revision.provider || draft.provider || null,
  errorMessage: null,
  rawAi: revision.rawAiPreview || null
});

return [{
  json: {
    ...$json,
    ...draft,
    contentId,
    revisionId,
    title: revision.title || draft.title,
    script: revision.script || draft.script,
    voiceover: revision.voiceover || draft.voiceover,
    status: 'approved_pending_video',
    finalVideoUrl,
    previewUrl,
    targetDurationSec: draft.targetDurationSec || 45,
    actualDurationSec: draft.actualDurationSec || 0,
    hashtags: draft.hashtags || [],
    caption: draft.caption || '',
    publishPayload: draft.publishPayload,
    chatId: draft.chatId
  }
}];

const staticData = getWorkflowStaticData('global');
if (!staticData.drafts) staticData.drafts = {};
if (!staticData.logs) staticData.logs = [];
if (!staticData.analytics) staticData.analytics = {};

const contentId = $json.contentId;
const revisionId = $json.revisionId;
const draft = staticData.drafts[contentId] || $json.draft;

if (!draft) {
