function truncateRaw(value) {
  return String(value || '').slice(0, 300);
}

function asText(value) {
  if (typeof value === 'string') return value.trim();
  if (Array.isArray(value)) {
    return value
      .map((item) => {
        if (typeof item === 'string') return item;
        if (item && typeof item === 'object') {
          if (typeof item.text === 'string') return item.text;
          if (typeof item.content === 'string') return item.content;
        }
        return '';
      })
      .join('\n')
      .trim();
  }
  if (value && typeof value === 'object') {
    if (typeof value.text === 'string') return value.text.trim();
    if (typeof value.content === 'string') return value.content.trim();
  }
  return '';
}

function extractAiContent(payload) {
  const variants = [
    payload?.choices?.[0]?.message?.content,
    payload?.choices?.[0]?.text,
    payload?.data?.choices?.[0]?.message?.content,
    payload?.data?.choices?.[0]?.text,
    payload?.output_text,
    payload?.output
  ];
  for (const candidate of variants) {
    const text = asText(candidate);
    if (text) return text;
  }
  return '';
}

function parseStrictJson(rawAi) {
  let parsed;
  try {
    parsed = JSON.parse(rawAi);
  } catch (e) {
    const cleaned = String(rawAi)
      .replace(/^```json\s*/i, '')
      .replace(/^```\s*/i, '')
      .replace(/\s*```$/, '')
      .trim();
    parsed = JSON.parse(cleaned);
  }

  if (!parsed || typeof parsed !== 'object' || Array.isArray(parsed)) {
    throw new Error('AI fallback вернул не JSON объект');
  }

  if (Object.keys(parsed).length === 0) {
    throw new Error('AI fallback вернул пустой JSON объект');
  }

  const title = typeof parsed.title === 'string' ? parsed.title.trim() : '';
  const script = typeof parsed.script === 'string' ? parsed.script.trim() : '';
  const voiceover = typeof parsed.voiceover === 'string' ? parsed.voiceover.trim() : '';

  if (!title || !script || !voiceover) {
    throw new Error('В JSON fallback отсутствуют обязательные поля title/script/voiceover');
  }

  return { title, script, voiceover };
}

function evaluatePayload(payload) {
  let aiHttpOk = true;
  let rawAi = '';
  let errorMessage = '';

  try {
    if (payload?.error) {
      aiHttpOk = false;
      const errText = payload.error.message || payload.error.description || JSON.stringify(payload.error);
      throw new Error(`AI fallback HTTP error: ${errText}`);
    }

    const hasChoices =
      (Array.isArray(payload?.choices) && payload.choices.length > 0) ||
      (Array.isArray(payload?.data?.choices) && payload.data.choices.length > 0);
    const hasAlternative = typeof payload?.output_text === 'string' || Array.isArray(payload?.output);

    if (!hasChoices && !hasAlternative) {
      aiHttpOk = false;
      throw new Error('AI fallback response has no choices/content');
    }

    rawAi = extractAiContent(payload);
    if (!rawAi) {
      throw new Error('AI fallback вернул пустой content');
    }

    const parsed = parseStrictJson(rawAi);
    return {
      ok: true,
      aiHttpOk,
      aiParseOk: true,
      rawAi: truncateRaw(rawAi),
      ...parsed,
      errorMessage: null,
      userErrorMessage: ''
    };
  } catch (error) {
    errorMessage = error?.message || 'Unknown fallback parse error';
    return {
      ok: false,
      aiHttpOk,
      aiParseOk: false,
      rawAi: truncateRaw(rawAi),
      title: '',
      script: '',
      voiceover: '',
      errorMessage,
      userErrorMessage: 'Ошибка на этапе: AI'
    };
  }
}

