  .filter(Boolean);

let sceneTexts = rawSegments.length ? rawSegments.slice(0, maxScenes) : [sourceText];

while (sceneTexts.length < minScenes) {
  const seed = sceneTexts[sceneTexts.length - 1] || sourceText;
  const suffix = sceneTexts.length % 2 === 0
    ? 'Добавь конкретный шаг и наглядный пример.'
    : 'Сделай акцент на пользе и практическом результате.';
  sceneTexts.push(`${seed} ${suffix}`.trim());
}

if (sceneTexts.length > maxScenes) {
  const head = sceneTexts.slice(0, maxScenes - 1);
  const mergedTail = sceneTexts.slice(maxScenes - 1).join(' ');
  sceneTexts = [...head, mergedTail];
}

sceneTexts = sceneTexts
  .map((t) => String(t || '').replace(/\s+/g, ' ').trim())
  .filter(Boolean)
  .slice(0, maxScenes);

if (sceneTexts.length < minScenes) {
  return [{
    json: {
      ...$json,
      stage: 'ContentPlan',
      stageOk: false,
      errorMessage: 'content_plan_not_enough_scenes'
    }
  }];
}

function clamp(value, min, max) {
  return Math.max(min, Math.min(max, value));
}

function allocateDurations(sceneCount, target) {
  const normalizedTarget = clamp(Math.round(target), minDurationSec, maxDurationSec);
  const base = Math.floor(normalizedTarget / sceneCount);
  let remainder = normalizedTarget - base * sceneCount;
  const durations = [];

  for (let i = 0; i < sceneCount; i += 1) {
    let d = base + (remainder > 0 ? 1 : 0);
    if (remainder > 0) remainder -= 1;
    d = clamp(d, 4, 12);
    durations.push(d);
  }

  return durations;
}

function sumDurations(values) {
  return values.reduce((sum, v) => sum + Number(v || 0), 0);
}

let durations = allocateDurations(sceneTexts.length, targetDurationSec);
let actualDurationSec = sumDurations(durations);

if (actualDurationSec < minDurationSec || actualDurationSec > maxDurationSec) {
  const correctionTarget = clamp(actualDurationSec, minDurationSec, maxDurationSec);
  durations = allocateDurations(sceneTexts.length, correctionTarget);
  actualDurationSec = sumDurations(durations);
}

if (actualDurationSec < minDurationSec || actualDurationSec > maxDurationSec) {
