function clamp(v, min, max) {
  return Math.min(max, Math.max(min, v));
}

function sumDuration(list) {
  return list.reduce((sum, s) => sum + Number(s.durationSec || 0), 0);
}

function ensureSceneShape(scene, idx) {
  const text = String(scene?.sceneText || scene?.text || '').trim() || `Сцена ${idx + 1}`;
  return {
    order: idx + 1,
    sceneText: text,
    durationSec: Number(scene?.durationSec || 0),
    imagePrompt: String(scene?.imagePrompt || `Vertical 9:16 cinematic frame, scene: ${text}`).trim(),
    videoPrompt: String(scene?.videoPrompt || `Vertical 9:16 smooth motion, scene: ${text}`).trim()
  };
}

function distributeDurations(count, target) {
  const safeTarget = clamp(Number(target || 45), minDurationSec, maxDurationSec);
  const base = Math.floor(safeTarget / count);
  let remainder = safeTarget - base * count;
  const durations = [];
  for (let i = 0; i < count; i += 1) {
    let d = base + (remainder > 0 ? 1 : 0);
    remainder -= 1;
    d = clamp(d, 4, 12);
    durations.push(d);
  }
  return durations;
}

function normalizeSceneCount(inputScenes) {
  let out = inputScenes.map(ensureSceneShape);

  const seed = String($json.voiceover || $json.script || $json.title || 'Основной тезис ролика').trim();

  while (out.length < minScenes) {
    const last = out[out.length - 1]?.sceneText || seed;
    out.push(ensureSceneShape({ sceneText: `${last}. Дополняем практической деталью.` }, out.length));
  }

  if (out.length > maxScenes) {
    const head = out.slice(0, maxScenes - 1);
    const tailText = out.slice(maxScenes - 1).map((s) => s.sceneText).join(' ');
    const last = ensureSceneShape({ sceneText: tailText }, maxScenes - 1);
    out = [...head, last];
  }

  return out.map(ensureSceneShape);
}

targetDurationSec = clamp(targetDurationSec, minDurationSec, maxDurationSec);
scenes = normalizeSceneCount(scenes.length ? scenes : [{ sceneText: $json.script || $json.voiceover || $json.title || 'Основной тезис ролика' }]);
let actualDurationSec = sumDuration(scenes);

let corrected = false;
