function normalizeTag(tag) {
  const t = String(tag || '').trim().toLowerCase().replace(/\s+/g, '');
  if (!t) return '';
  const withHash = t.startsWith('#') ? t : `#${t}`;
  return withHash.replace(/[^#a-zа-яё0-9_]/gi, '');
}

