let blockedByRevisionLimit = false;
let preparationError = '';
let nextRevisionId = null;

if (!draft) {
  preparationError = 'Не найден черновик для пересоздания.';
} else {
  const revisionCount = Number(draft.revisionCount || 1);
  if (revisionCount >= MAX_REVISIONS) {
    blockedByRevisionLimit = true;
    preparationError = 'Лимит переработок достигнут. Начни новый запрос.';
  } else {
    nextRevisionId = `rev${revisionCount + 1}`;

    draft.status = 'needs_revision';
    draft.revisionRequestedAt = now;
    draft.revisionReason = 'Пересоздать финальное видео';
    draft.updatedAt = now;

    const currentRevision = draft.revisions?.[revisionId];
    if (currentRevision) {
      currentRevision.status = 'needs_revision';
      currentRevision.revisionRequestedAt = now;
    }

    staticData.drafts[contentId] = draft;
  }
}

staticData.logs.push({
  timestamp: now,
  event: blockedByRevisionLimit ? 'revision_limit_reached' : 'recreate',
  contentId: contentId || null,
  revisionId: nextRevisionId || revisionId || null,
  revisionReason: 'Пересоздать финальное видео',
  contentMode: draft?.contentMode || null,
  voiceMode: draft?.voiceMode || null,
  status: blockedByRevisionLimit ? 'error' : 'needs_revision',
