function findUrls(obj, out = []) {
  if (!obj) return out;
  if (typeof obj === 'string' && obj.startsWith('http')) {
    out.push(obj);
    return out;
  }
  if (Array.isArray(obj)) {
    for (const item of obj) findUrls(item, out);
    return out;
  }
  if (typeof obj === 'object') {
    for (const key of Object.keys(obj)) findUrls(obj[key], out);
  }
  return out;
}

